# scripts/aims_kpi_report.py — generates ISO 42001 Clause 9 KPI report

import anthropic, json, datetime

def weekly_kpi_report(
    total_outputs: int,
    human_overrides: int,
    hallucinations_found: int,
    sampled: int,
    pii_alerts: int,
) -> dict:
    report = {
        "period": datetime.date.today().isoformat(),
        "kpis": {
            "human_override_rate": round(human_overrides / max(total_outputs, 1) * 100, 2),
            "hallucination_rate_pct": round(hallucinations_found / max(sampled, 1) * 100, 3),
            "pii_alerts": pii_alerts,
        },
        "thresholds": {
            "human_override_rate": {"target": 5.0, "pass": human_overrides / max(total_outputs, 1) * 100 < 5.0},
            "hallucination_rate_pct": {"target": 0.1, "pass": hallucinations_found / max(sampled, 1) * 100 < 0.1},
            "pii_alerts": {"target": 0, "pass": pii_alerts == 0},
        },
    }
    all_pass = all(v["pass"] for v in report["thresholds"].values())
    report["overall"] = "PASS" if all_pass else "FAIL"
    return report

# Example run
if __name__ == "__main__":
    rpt = weekly_kpi_report(
        total_outputs=12450, human_overrides=287,
        hallucinations_found=2, sampled=500, pii_alerts=0,
    )
    print(json.dumps(rpt, indent=2))
